-- Upserts for concept_exercises: Conceptual Physics chapters 25, 26, 27, 29, 30, 31
-- Generated for Unit 6 (Waves, Sound & Light) reading ingestion.

INSERT INTO concept_exercises (chapter, title, text_pdf_url, page_offset, sections, answer_key)
VALUES (
  25,
  'Vibrations and Waves',
  'https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte25.pdf',
  489,
  $ch25s$[{"id": "25.1", "label": "Vibration of a Pendulum", "pageStart": 491, "pageEnd": 491, "items": [{"n": 1, "type": "fill_in", "prompt": "The time of a back-and-forth swing of a pendulum is called its ______.", "blanks": 1}, {"n": 2, "type": "fill_in", "prompt": "The period of a pendulum depends only on the ______ of the pendulum and the acceleration of ______.", "blanks": 2}, {"n": 3, "type": "true_false", "prompt": "Galileo discovered that the period of a pendulum depends on its mass."}, {"n": 4, "type": "multiple_choice", "prompt": "Compared with a short pendulum, a long pendulum swings back and forth", "options": [{"letter": "a", "text": "with a shorter period — more frequently"}, {"letter": "b", "text": "with a longer period — less frequently"}, {"letter": "c", "text": "with exactly the same period"}]}, {"n": 5, "type": "short_answer", "prompt": "Why do long-legged animals such as giraffes and horses run with a slower gait than short-legged animals?"}]}, {"id": "25.2", "label": "Wave Description", "pageStart": 491, "pageEnd": 493, "items": [{"n": 6, "type": "fill_in", "prompt": "The back-and-forth vibratory motion of a swinging pendulum is called simple ______ motion.", "blanks": 1}, {"n": 7, "type": "fill_in", "prompt": "The high points on a wave are called ______, and the low points are called ______.", "blanks": 2}, {"n": 8, "type": "true_false", "prompt": "The amplitude of a wave is the distance from a crest to a trough."}, {"n": 9, "type": "multiple_choice", "prompt": "The unit of frequency, one cycle per second, is called the", "options": [{"letter": "a", "text": "watt"}, {"letter": "b", "text": "hertz"}, {"letter": "c", "text": "joule"}, {"letter": "d", "text": "decibel"}]}, {"n": 10, "type": "true_false", "prompt": "Frequency and period are inverses of each other."}, {"n": 11, "type": "short_answer", "prompt": "A pendulum makes two vibrations in one second. What is its period?"}]}, {"id": "25.3", "label": "Wave Motion", "pageStart": 493, "pageEnd": 494, "items": [{"n": 12, "type": "fill_in", "prompt": "When energy is transferred by a wave from a vibrating source to a distant receiver, there is no transfer of ______ between the two points.", "blanks": 1}, {"n": 13, "type": "fill_in", "prompt": "The energy transferred by a wave is carried by a ______ in a medium.", "blanks": 1}, {"n": 14, "type": "true_false", "prompt": "After a water wave passes, the water is where it was before the wave passed."}, {"n": 15, "type": "multiple_choice", "prompt": "When you shake the end of a stretched string up and down, what travels along the length of the string?", "options": [{"letter": "a", "text": "the parts of the string itself"}, {"letter": "b", "text": "the disturbance"}, {"letter": "c", "text": "the air surrounding the string"}]}, {"n": 16, "type": "short_answer", "prompt": "A leaf is floating on a pond as a wave passes. Describe the leaf's motion."}]}, {"id": "25.4", "label": "Wave Speed", "pageStart": 495, "pageEnd": 496, "items": [{"n": 17, "type": "fill_in", "prompt": "You can calculate the speed of a wave by multiplying the wavelength by the ______.", "blanks": 1}, {"n": 18, "type": "fill_in", "prompt": "In the equation v = λf, the Greek letter lambda (λ) stands for the ______.", "blanks": 1}, {"n": 19, "type": "true_false", "prompt": "During a concert, you hear the high notes in a chord before you hear the low notes."}, {"n": 20, "type": "multiple_choice", "prompt": "A wave has a wavelength of 3 meters, and two crests pass a stationary point each second. Its speed is", "options": [{"letter": "a", "text": "1.5 m/s"}, {"letter": "b", "text": "5 m/s"}, {"letter": "c", "text": "6 m/s"}, {"letter": "d", "text": "0.67 m/s"}]}, {"n": 21, "type": "true_false", "prompt": "For sound waves all traveling at the same speed, long wavelengths have low frequencies and short wavelengths have high frequencies."}]}, {"id": "25.5", "label": "Transverse Waves", "pageStart": 497, "pageEnd": 497, "items": [{"n": 22, "type": "fill_in", "prompt": "Whenever the motion of the medium is at right angles to the direction in which a wave travels, the wave is a ______ wave.", "blanks": 1}, {"n": 23, "type": "fill_in", "prompt": "Radio waves and light are ______ waves that are transverse.", "blanks": 1}, {"n": 24, "type": "true_false", "prompt": "In a transverse wave, the medium vibrates parallel to the direction the wave travels."}, {"n": 25, "type": "multiple_choice", "prompt": "Which of these is an example of a transverse wave?", "options": [{"letter": "a", "text": "a sound wave in air"}, {"letter": "b", "text": "a wave in the stretched string of a musical instrument"}, {"letter": "c", "text": "a compression traveling along a spring"}]}]}, {"id": "25.6", "label": "Longitudinal Waves", "pageStart": 497, "pageEnd": 497, "items": [{"n": 26, "type": "fill_in", "prompt": "When the particles of a medium oscillate parallel to the direction the wave travels, the wave is a ______ wave.", "blanks": 1}, {"n": 27, "type": "fill_in", "prompt": "______ waves are longitudinal waves.", "blanks": 1}, {"n": 28, "type": "true_false", "prompt": "Both transverse and longitudinal waves can be demonstrated with a loosely coiled spring."}, {"n": 29, "type": "multiple_choice", "prompt": "To demonstrate a longitudinal wave with a coiled spring, you shake the end of the spring", "options": [{"letter": "a", "text": "up and down"}, {"letter": "b", "text": "in and out, along the spring's length"}, {"letter": "c", "text": "in a circle"}]}]}, {"id": "25.7", "label": "Interference", "pageStart": 498, "pageEnd": 499, "items": [{"n": 30, "type": "fill_in", "prompt": "A regular arrangement of places where wave effects are increased, decreased, or neutralized is called an ______ pattern.", "blanks": 1}, {"n": 31, "type": "fill_in", "prompt": "In ______ interference, the crest of one wave overlaps the crest of another; in ______ interference, the crest of one wave overlaps the trough of another.", "blanks": 2}, {"n": 32, "type": "true_false", "prompt": "More than one wave can exist at the same time in the same space."}, {"n": 33, "type": "multiple_choice", "prompt": "When waves from two sources arrive out of phase, the result is", "options": [{"letter": "a", "text": "reinforcement and increased amplitude"}, {"letter": "b", "text": "regions of zero amplitude — cancellation"}, {"letter": "c", "text": "a wave that travels faster"}]}, {"n": 34, "type": "short_answer", "prompt": "Is interference restricted to water waves, or is it a property of all waves?"}]}, {"id": "25.8", "label": "Standing Waves", "pageStart": 500, "pageEnd": 501, "items": [{"n": 35, "type": "fill_in", "prompt": "A wave that appears to stay in one place and does not seem to move through the medium is a ______ wave.", "blanks": 1}, {"n": 36, "type": "fill_in", "prompt": "The stationary points on a standing wave are called ______, and the positions with the largest amplitudes are called ______.", "blanks": 2}, {"n": 37, "type": "true_false", "prompt": "Standing waves are the result of interference between incident and reflected waves."}, {"n": 38, "type": "multiple_choice", "prompt": "A standing wave forms in a vibrating medium only when", "options": [{"letter": "a", "text": "the source moves faster than the wave"}, {"letter": "b", "text": "half a wavelength, or a multiple of half a wavelength, fits exactly into the length of the medium"}, {"letter": "c", "text": "the amplitude is large enough"}]}, {"n": 39, "type": "true_false", "prompt": "Standing waves can be produced only in transverse waves, never in longitudinal waves."}]}, {"id": "25.9", "label": "The Doppler Effect", "pageStart": 501, "pageEnd": 503, "items": [{"n": 40, "type": "fill_in", "prompt": "The apparent change in frequency due to the motion of the source is called the ______ effect.", "blanks": 1}, {"n": 41, "type": "fill_in", "prompt": "For light, an increase in frequency is called a ______ shift and a decrease in frequency is called a ______ shift.", "blanks": 2}, {"n": 42, "type": "true_false", "prompt": "As a wave source approaches, an observer encounters waves with a higher frequency."}, {"n": 43, "type": "true_false", "prompt": "The Doppler effect is caused by a change in wave speed."}, {"n": 44, "type": "multiple_choice", "prompt": "Police radar determines a car's speed by comparing", "options": [{"letter": "a", "text": "the loudness of the emitted and reflected waves"}, {"letter": "b", "text": "the frequency of the radar waves with the frequency of the reflected waves"}, {"letter": "c", "text": "the brightness of the headlights"}]}, {"n": 45, "type": "short_answer", "prompt": "When a firetruck passes you with its siren on, what happens to the pitch you hear, and why?"}]}, {"id": "25.10", "label": "Bow Waves", "pageStart": 504, "pageEnd": 504, "items": [{"n": 46, "type": "fill_in", "prompt": "The V-shaped pattern made by overlapping wave crests behind a source moving faster than the waves is called a ______ wave.", "blanks": 1}, {"n": 47, "type": "true_false", "prompt": "A bow wave occurs when a wave source moves faster than the waves it produces."}, {"n": 48, "type": "multiple_choice", "prompt": "When a bug swims exactly as fast as the water waves it makes, the wave crests", "options": [{"letter": "a", "text": "get ahead of the bug"}, {"letter": "b", "text": "pile up directly in front of the bug"}, {"letter": "c", "text": "disappear entirely"}]}, {"n": 49, "type": "true_false", "prompt": "An airplane cannot fly faster than the speed of sound because the sound barrier is a real physical wall."}]}, {"id": "25.11", "label": "Shock Waves", "pageStart": 505, "pageEnd": 506, "items": [{"n": 50, "type": "fill_in", "prompt": "A supersonic aircraft generates a three-dimensional ______ wave made of overlapping spheres that form a cone.", "blanks": 1}, {"n": 51, "type": "fill_in", "prompt": "The sharp crack heard when the shock wave from a supersonic aircraft reaches a listener is called a ______.", "blanks": 1}, {"n": 52, "type": "true_false", "prompt": "A sonic boom is produced only at the single moment an aircraft breaks through the sound barrier."}, {"n": 53, "type": "multiple_choice", "prompt": "Which of the following produces a small sonic boom?", "options": [{"letter": "a", "text": "the tip of a circus whip cracking"}, {"letter": "b", "text": "a slower-than-sound passenger jet"}, {"letter": "c", "text": "a loud stereo speaker"}]}, {"n": 54, "type": "short_answer", "prompt": "Why don't we hear a sonic boom from a slower-than-sound aircraft?"}]}]$ch25s$::jsonb,
  $ch25k${"1": ["period"], "2": ["length", "gravity"], "3": "false", "4": "b", "5": {"model": "Legs swing like pendulums; a longer pendulum has a longer period, so longer legs swing back and forth less frequently."}, "6": ["harmonic"], "7": ["crests", "troughs"], "8": "false", "9": "b", "10": "true", "11": {"model": "Its period is 1/2 second, because period = 1/frequency."}, "12": ["matter"], "13": ["disturbance"], "14": "true", "15": "b", "16": {"model": "The leaf moves up and down with the water but does not travel along with the wave."}, "17": ["frequency"], "18": ["wavelength"], "19": "false", "20": "c", "21": "true", "22": ["transverse"], "23": ["electromagnetic"], "24": "false", "25": "b", "26": ["longitudinal"], "27": ["sound"], "28": "true", "29": "b", "30": ["interference"], "31": ["constructive", "destructive"], "32": "true", "33": "b", "34": {"model": "Interference is characteristic of all wave motion — water waves, sound waves, and light waves all show it."}, "35": ["standing"], "36": ["nodes", "antinodes"], "37": "true", "38": "b", "39": "false", "40": ["doppler"], "41": ["blue", "red"], "42": "true", "43": "false", "44": "b", "45": {"model": "The pitch is higher as it approaches and drops as it moves away, because the wave crests reach you more frequently, then less frequently."}, "46": ["bow"], "47": "true", "48": "b", "49": "false", "50": ["shock"], "51": ["sonic boom"], "52": "false", "53": "a", "54": {"model": "Its sound crests reach our ears one at a time as a continuous tone; only when the craft moves faster than sound do the crests overlap and arrive in a single burst."}}$ch25k$::jsonb
)
ON CONFLICT (chapter) DO UPDATE SET
  title = EXCLUDED.title,
  text_pdf_url = EXCLUDED.text_pdf_url,
  page_offset = EXCLUDED.page_offset,
  sections = EXCLUDED.sections,
  answer_key = EXCLUDED.answer_key,
  updated_at = now();

INSERT INTO concept_exercises (chapter, title, text_pdf_url, page_offset, sections, answer_key)
VALUES (
  26,
  'Sound',
  'https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte26.pdf',
  513,
  $ch26s$[{"id": "26.1", "label": "The Origin of Sound", "pageStart": 515, "pageEnd": 515, "items": [{"n": 1, "type": "fill_in", "prompt": "All sounds originate in the ______ of material objects.", "blanks": 1}, {"n": 2, "type": "true_false", "prompt": "A high-pitched sound, like that from a piccolo, has a high vibration frequency."}, {"n": 3, "type": "fill_in", "prompt": "Sound waves with frequencies below 20 hertz are called ______, and those above 20,000 hertz are called ______.", "blanks": 2}, {"n": 4, "type": "multiple_choice", "prompt": "A young person can normally hear pitches with frequencies from about", "options": [{"letter": "a", "text": "20 to 20,000 hertz"}, {"letter": "b", "text": "2 to 2,000 hertz"}, {"letter": "c", "text": "200 to 2,000,000 hertz"}]}, {"n": 5, "type": "short_answer", "prompt": "As we grow older, what happens to our hearing range?"}]}, {"id": "26.2", "label": "Sound in Air", "pageStart": 515, "pageEnd": 516, "items": [{"n": 6, "type": "fill_in", "prompt": "A pulse of compressed air is called a ______; a pulse of low-pressure air is called a ______.", "blanks": 2}, {"n": 7, "type": "fill_in", "prompt": "As a source of sound vibrates, a series of compressions and rarefactions travels ______ from the source.", "blanks": 1}, {"n": 8, "type": "true_false", "prompt": "In a sound wave, the air itself travels across the room from the source to your ear."}, {"n": 9, "type": "multiple_choice", "prompt": "Quickly opening a door at one end of a long room sends what across the room?", "options": [{"letter": "a", "text": "a rarefaction"}, {"letter": "b", "text": "a compression"}, {"letter": "c", "text": "a vacuum"}]}, {"n": 10, "type": "true_false", "prompt": "The flapping curtain shows that a pulse — not the medium — travels across the room."}]}, {"id": "26.3", "label": "Media That Transmit Sound", "pageStart": 517, "pageEnd": 517, "items": [{"n": 11, "type": "fill_in", "prompt": "Sound cannot travel in a ______ because the transmission of sound requires a medium.", "blanks": 1}, {"n": 12, "type": "fill_in", "prompt": "In general, sound is transmitted faster in liquids than in gases, and still faster in ______.", "blanks": 1}, {"n": 13, "type": "true_false", "prompt": "Solids and liquids are generally better conductors of sound than air."}, {"n": 14, "type": "multiple_choice", "prompt": "The boy watching the ringing bell in the jar can no longer hear it when", "options": [{"letter": "a", "text": "the jar is sealed"}, {"letter": "b", "text": "the air is removed from the jar"}, {"letter": "c", "text": "the jar is cooled"}]}, {"n": 15, "type": "short_answer", "prompt": "Why can you hear a boat's motor more clearly under water than above water?"}]}, {"id": "26.4", "label": "Speed of Sound", "pageStart": 518, "pageEnd": 518, "items": [{"n": 16, "type": "fill_in", "prompt": "The speed of sound in dry air at 0°C is about ______ meters per second.", "blanks": 1}, {"n": 17, "type": "fill_in", "prompt": "The speed of sound in a solid material depends not on the material's density but on its ______.", "blanks": 1}, {"n": 18, "type": "true_false", "prompt": "Sound travels about fifteen times faster in steel than in air."}, {"n": 19, "type": "multiple_choice", "prompt": "For each degree increase in air temperature above 0°C, the speed of sound in air increases by about", "options": [{"letter": "a", "text": "0.60 m/s"}, {"letter": "b", "text": "6.0 m/s"}, {"letter": "c", "text": "60 m/s"}]}, {"n": 20, "type": "true_false", "prompt": "Lighter particles such as hydrogen molecules and helium atoms transmit sound more quickly than heavier gases."}]}, {"id": "26.5", "label": "Loudness", "pageStart": 519, "pageEnd": 519, "items": [{"n": 21, "type": "fill_in", "prompt": "The unit of intensity for sound is the ______.", "blanks": 1}, {"n": 22, "type": "fill_in", "prompt": "Sound ______ is objective and measured by instruments; ______ is a physiological sensation sensed in the brain.", "blanks": 2}, {"n": 23, "type": "true_false", "prompt": "A 20-dB sound is twice as intense as a 10-dB sound."}, {"n": 24, "type": "multiple_choice", "prompt": "Starting from the threshold of hearing, an increase of each 10 dB means sound intensity increases by a factor of", "options": [{"letter": "a", "text": "2"}, {"letter": "b", "text": "10"}, {"letter": "c", "text": "100"}]}, {"n": 25, "type": "short_answer", "prompt": "At about what decibel level does physiological hearing damage begin?"}]}, {"id": "26.6", "label": "Natural Frequency", "pageStart": 520, "pageEnd": 520, "items": [{"n": 26, "type": "fill_in", "prompt": "The frequency at which an object vibrates when it is disturbed is its ______ frequency.", "blanks": 1}, {"n": 27, "type": "fill_in", "prompt": "An object's natural frequency depends on its shape and its ______.", "blanks": 1}, {"n": 28, "type": "true_false", "prompt": "A natural frequency is one at which minimum energy is required to produce forced vibrations."}, {"n": 29, "type": "multiple_choice", "prompt": "A dropped wrench and a dropped baseball bat make distinctly different sounds because", "options": [{"letter": "a", "text": "each vibrates at its own special set of frequencies"}, {"letter": "b", "text": "the floor vibrates randomly"}, {"letter": "c", "text": "sound travels at a different speed for each object"}]}]}, {"id": "26.7", "label": "Forced Vibration", "pageStart": 520, "pageEnd": 520, "items": [{"n": 30, "type": "fill_in", "prompt": "When an object is made to vibrate by another vibrating object that is nearby, the result is a ______ vibration.", "blanks": 1}, {"n": 31, "type": "fill_in", "prompt": "Sounding boards are an important part of all stringed instruments because they are forced into ______ and produce the sound.", "blanks": 1}, {"n": 32, "type": "true_false", "prompt": "Striking a tuning fork while holding its base against a tabletop makes the sound louder."}, {"n": 33, "type": "multiple_choice", "prompt": "Without the guitar's wooden body, the sound of vibrating guitar strings would be faint because", "options": [{"letter": "a", "text": "the strings would stop vibrating immediately"}, {"letter": "b", "text": "the strings alone set little air in motion; the body acts as a sounding board"}, {"letter": "c", "text": "wood absorbs all the sound"}]}]}, {"id": "26.8", "label": "Resonance", "pageStart": 521, "pageEnd": 522, "items": [{"n": 34, "type": "fill_in", "prompt": "When the frequency of a forced vibration matches an object's natural frequency and a dramatic increase in amplitude occurs, the phenomenon is called ______.", "blanks": 1}, {"n": 35, "type": "fill_in", "prompt": "When pumping a swing, more important than the force with which you pump is the ______.", "blanks": 1}, {"n": 36, "type": "true_false", "prompt": "Putty resonates well because it is not elastic."}, {"n": 37, "type": "multiple_choice", "prompt": "The 1940 Tacoma Narrows Bridge disaster is attributed to", "options": [{"letter": "a", "text": "an earthquake"}, {"letter": "b", "text": "wind-generated resonance"}, {"letter": "c", "text": "too much traffic"}]}, {"n": 38, "type": "short_answer", "prompt": "Why is it customary for troops to break step when crossing a bridge?"}]}, {"id": "26.9", "label": "Interference", "pageStart": 522, "pageEnd": 523, "items": [{"n": 39, "type": "fill_in", "prompt": "For sound, the crest of a wave corresponds to a ______, and the trough corresponds to a ______.", "blanks": 2}, {"n": 40, "type": "fill_in", "prompt": "When destructive interference occurs with sound waves, the listener hears a ______ sound or no sound at all.", "blanks": 1}, {"n": 41, "type": "true_false", "prompt": "Sound waves cannot cancel other sound waves."}, {"n": 42, "type": "multiple_choice", "prompt": "Noise-canceling earphones quiet noise by", "options": [{"letter": "a", "text": "blocking all air from reaching the ear"}, {"letter": "b", "text": "producing mirror-image wave patterns that neutralize the noise"}, {"letter": "c", "text": "playing music louder than the noise"}]}, {"n": 43, "type": "true_false", "prompt": "Dead spots in poorly designed theaters are zones of low amplitude caused by destructive interference."}]}, {"id": "26.10", "label": "Beats", "pageStart": 524, "pageEnd": 525, "items": [{"n": 44, "type": "fill_in", "prompt": "The periodic variation in the loudness of sound heard when two tones of slightly different frequency are sounded together is called ______.", "blanks": 1}, {"n": 45, "type": "fill_in", "prompt": "When a 264-Hz tuning fork and a 262-Hz tuning fork are sounded together, the beat frequency is ______ Hz.", "blanks": 1}, {"n": 46, "type": "true_false", "prompt": "A piano tuner listens for beats between a standard tuning fork and a piano string, and tunes until the beats disappear."}, {"n": 47, "type": "multiple_choice", "prompt": "Beats are an interesting and special case of", "options": [{"letter": "a", "text": "refraction"}, {"letter": "b", "text": "interference"}, {"letter": "c", "text": "resonance"}]}, {"n": 48, "type": "short_answer", "prompt": "You take 70 steps per minute and a friend takes 72 steps per minute. How many times per minute are you in step, and why?"}]}]$ch26s$::jsonb,
  $ch26k${"1": ["vibrations"], "2": "true", "3": ["infrasonic", "ultrasonic"], "4": "a", "5": {"model": "It shrinks, especially at the high-frequency end."}, "6": ["compression", "rarefaction"], "7": ["outward"], "8": "false", "9": "b", "10": "true", "11": ["vacuum"], "12": ["solids"], "13": "true", "14": "b", "15": {"model": "Liquids are good conductors of sound — much better than air — so the sound travels well through the water to your submerged ear."}, "16": ["330"], "17": ["elasticity"], "18": "true", "19": "a", "20": "true", "21": ["decibel"], "22": ["intensity", "loudness"], "23": "false", "24": "b", "25": {"model": "Hearing damage begins at exposure to about 85 decibels."}, "26": ["natural"], "27": ["elasticity"], "28": "true", "29": "a", "30": ["forced"], "31": ["vibration"], "32": "true", "33": "b", "34": ["resonance"], "35": ["timing"], "36": "false", "37": "b", "38": {"model": "Marching in rhythm with the bridge's natural frequency could cause resonance and dangerously large amplitudes — as happened in 1831."}, "39": ["compression", "rarefaction"], "40": ["fainter"], "41": "false", "42": "b", "43": "true", "44": ["beats"], "45": ["2"], "46": "true", "47": "b", "48": {"model": "Twice per minute — the number of times in step per unit time equals the difference between the two frequencies."}}$ch26k$::jsonb
)
ON CONFLICT (chapter) DO UPDATE SET
  title = EXCLUDED.title,
  text_pdf_url = EXCLUDED.text_pdf_url,
  page_offset = EXCLUDED.page_offset,
  sections = EXCLUDED.sections,
  answer_key = EXCLUDED.answer_key,
  updated_at = now();

INSERT INTO concept_exercises (chapter, title, text_pdf_url, page_offset, sections, answer_key)
VALUES (
  27,
  'Light',
  'https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte27.pdf',
  531,
  $ch27s$[{"id": "27.1", "label": "Early Concepts of Light", "pageStart": 533, "pageEnd": 533, "items": [{"n": 1, "type": "fill_in", "prompt": "Photons are massless bundles of concentrated ______ energy.", "blanks": 1}, {"n": 2, "type": "fill_in", "prompt": "Scientists now agree that light has a ______ nature, part particle and part wave.", "blanks": 1}, {"n": 3, "type": "true_false", "prompt": "Socrates and Plato thought that vision resulted from streamers or filaments emitted by the eye."}, {"n": 4, "type": "multiple_choice", "prompt": "Who published a theory in 1905 explaining the photoelectric effect, in which light consists of photons?", "options": [{"letter": "a", "text": "Newton"}, {"letter": "b", "text": "Huygens"}, {"letter": "c", "text": "Einstein"}, {"letter": "d", "text": "Empedocles"}]}, {"n": 5, "type": "true_false", "prompt": "The wave theory of light became the accepted theory in the nineteenth century."}]}, {"id": "27.2", "label": "The Speed of Light", "pageStart": 534, "pageEnd": 535, "items": [{"n": 6, "type": "fill_in", "prompt": "The first demonstration that light travels at a finite speed was supplied by the Danish astronomer Olaus ______.", "blanks": 1}, {"n": 7, "type": "fill_in", "prompt": "The speed of light in a vacuum is ______ km/s.", "blanks": 1}, {"n": 8, "type": "true_false", "prompt": "Michelson measured the speed of light using a spinning octagonal mirror and a stationary mirror on a mountain 35 km away."}, {"n": 9, "type": "multiple_choice", "prompt": "The distance light travels in one year is called a", "options": [{"letter": "a", "text": "parsec"}, {"letter": "b", "text": "light-year"}, {"letter": "c", "text": "light-minute"}]}, {"n": 10, "type": "true_false", "prompt": "Light takes 8 minutes to travel from the sun to Earth."}, {"n": 11, "type": "short_answer", "prompt": "In Roemer's measurements, why did Io seem to pass into Jupiter's shadow 22 minutes late when Earth was farthest from Jupiter?"}]}, {"id": "27.3", "label": "Electromagnetic Waves", "pageStart": 536, "pageEnd": 536, "items": [{"n": 12, "type": "fill_in", "prompt": "Light is energy that is emitted by accelerating electric ______, often electrons in atoms.", "blanks": 1}, {"n": 13, "type": "fill_in", "prompt": "Electromagnetic waves of frequencies lower than the red of visible light are called ______; waves of frequencies higher than violet are called ______.", "blanks": 2}, {"n": 14, "type": "true_false", "prompt": "Visible light makes up most of the electromagnetic spectrum."}, {"n": 15, "type": "multiple_choice", "prompt": "Which list contains members of the electromagnetic spectrum?", "options": [{"letter": "a", "text": "radio waves, microwaves, X-rays, gamma rays"}, {"letter": "b", "text": "sound waves, water waves, slinky waves"}, {"letter": "c", "text": "compressions and rarefactions"}]}, {"n": 16, "type": "true_false", "prompt": "The lowest frequency of light we can see with our eyes appears red."}]}, {"id": "27.4", "label": "Light and Transparent Materials", "pageStart": 537, "pageEnd": 538, "items": [{"n": 17, "type": "fill_in", "prompt": "Materials that transmit light are ______.", "blanks": 1}, {"n": 18, "type": "fill_in", "prompt": "In water, light travels at ______% of its speed in a vacuum.", "blanks": 1}, {"n": 19, "type": "true_false", "prompt": "Electrons in glass have a natural vibration frequency in the ultraviolet range."}, {"n": 20, "type": "multiple_choice", "prompt": "Why is glass not transparent to ultraviolet light?", "options": [{"letter": "a", "text": "Ultraviolet resonates with the electrons in glass, and the energy is given up as heat"}, {"letter": "b", "text": "Ultraviolet moves too fast to enter the glass"}, {"letter": "c", "text": "Glass reflects all ultraviolet light back"}]}, {"n": 21, "type": "true_false", "prompt": "When light emerges from glass into air, it continues at the slower speed it had inside the glass."}, {"n": 22, "type": "short_answer", "prompt": "What causes the average speed of light to be lower in a transparent material than in a vacuum?"}]}, {"id": "27.5", "label": "Opaque Materials", "pageStart": 539, "pageEnd": 539, "items": [{"n": 23, "type": "fill_in", "prompt": "Materials that absorb light without reemission, and thus allow no light through them, are ______.", "blanks": 1}, {"n": 24, "type": "fill_in", "prompt": "In opaque materials, the coordinated vibrations given by light to atoms are turned into random kinetic energy, and the material becomes slightly ______.", "blanks": 1}, {"n": 25, "type": "true_false", "prompt": "Metals are shiny because their free electrons reemit the light that shines on them as visible reflection."}, {"n": 26, "type": "multiple_choice", "prompt": "You can get a sunburn on a cloudy day because", "options": [{"letter": "a", "text": "clouds emit their own ultraviolet light"}, {"letter": "b", "text": "clouds are semitransparent to ultraviolet"}, {"letter": "c", "text": "clouds focus sunlight like a lens"}]}, {"n": 27, "type": "true_false", "prompt": "Our atmosphere is almost opaque to high-frequency ultraviolet waves."}]}, {"id": "27.6", "label": "Shadows", "pageStart": 540, "pageEnd": 541, "items": [{"n": 28, "type": "fill_in", "prompt": "A thin beam of light is often called a ______.", "blanks": 1}, {"n": 29, "type": "fill_in", "prompt": "A total shadow is called an ______, and a partial shadow is called a ______.", "blanks": 2}, {"n": 30, "type": "true_false", "prompt": "A solar eclipse occurs when the moon's shadow falls on Earth."}, {"n": 31, "type": "multiple_choice", "prompt": "A lunar eclipse occurs when", "options": [{"letter": "a", "text": "the moon passes into Earth's shadow"}, {"letter": "b", "text": "Earth passes into the moon's shadow"}, {"letter": "c", "text": "the sun passes between Earth and the moon"}]}, {"n": 32, "type": "short_answer", "prompt": "Why can a lunar eclipse be seen by more people than a solar eclipse?"}]}, {"id": "27.7", "label": "Polarization", "pageStart": 542, "pageEnd": 543, "items": [{"n": 33, "type": "fill_in", "prompt": "The phenomenon of ______ demonstrates that light waves are transverse and not longitudinal.", "blanks": 1}, {"n": 34, "type": "fill_in", "prompt": "Glare that reflects from a horizontal surface, such as a road or water, is ______ polarized.", "blanks": 1}, {"n": 35, "type": "true_false", "prompt": "Light from a common source such as an incandescent lamp or a candle flame is polarized."}, {"n": 36, "type": "multiple_choice", "prompt": "Light will pass through a pair of polarizing filters when their polarization axes are", "options": [{"letter": "a", "text": "crossed at right angles"}, {"letter": "b", "text": "aligned"}, {"letter": "c", "text": "at any angle whatsoever"}]}, {"n": 37, "type": "true_false", "prompt": "The axes of Polaroid sunglasses are vertical so that horizontally polarized glare is eliminated."}]}, {"id": "27.8", "label": "Polarized Light and 3-D Viewing", "pageStart": 544, "pageEnd": 545, "items": [{"n": 38, "type": "fill_in", "prompt": "Vision in three dimensions depends on both eyes giving impressions ______, each viewing the scene from a slightly different angle.", "blanks": 1}, {"n": 39, "type": "fill_in", "prompt": "In a 3-D slide show, the two views are projected through polarizing filters with axes at ______ angles to each other.", "blanks": 1}, {"n": 40, "type": "true_false", "prompt": "To see the 3-D effect, the viewer wears polarizing eyeglasses with the lens axes at right angles."}, {"n": 41, "type": "multiple_choice", "prompt": "To the naked eye, the overlapping pictures of a 3-D projection look", "options": [{"letter": "a", "text": "perfectly sharp"}, {"letter": "b", "text": "blurry"}, {"letter": "c", "text": "upside down"}]}, {"n": 42, "type": "short_answer", "prompt": "What does the eye-brain system do with the two slightly different views in 3-D viewing?"}]}]$ch27s$::jsonb,
  $ch27k${"1": ["electromagnetic"], "2": ["dual"], "3": "true", "4": "c", "5": "true", "6": ["roemer"], "7": ["300,000"], "8": "true", "9": "b", "10": "true", "11": {"model": "The light was late, not the moon — it had to travel the extra distance across the diameter of Earth's orbit."}, "12": ["charges"], "13": ["infrared", "ultraviolet"], "14": "false", "15": "a", "16": "true", "17": ["transparent"], "18": ["75"], "19": "true", "20": "a", "21": "false", "22": {"model": "The time delay between the absorption and reemission of light by atoms in the material lowers its average speed."}, "23": ["opaque"], "24": ["warmer"], "25": "true", "26": "b", "27": "true", "28": ["ray"], "29": ["umbra", "penumbra"], "30": "true", "31": "a", "32": {"model": "A lunar eclipse can be seen by all observers on the nighttime half of Earth, while a solar eclipse is visible only in a small region of Earth."}, "33": ["polarization"], "34": ["horizontally"], "35": "false", "36": "b", "37": "true", "38": ["simultaneously"], "39": ["right"], "40": "true", "41": "b", "42": {"model": "It combines the two pictures and interprets them as a single picture with depth."}}$ch27k$::jsonb
)
