INSERT INTO concept_exercises (chapter, title, text_pdf_url, page_offset, sections, answer_key)
VALUES (
  29,
  'Reflection and Refraction',
  'https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte29.pdf',
  577,
  $ch29s$[{"id": "29.1", "label": "Reflection", "pageStart": 579, "pageEnd": 579, "items": [{"n": 1, "type": "fill_in", "prompt": "The return of a wave back into its original medium is called ______.", "blanks": 1}, {"n": 2, "type": "fill_in", "prompt": "When light shines perpendicularly on still water, about ______% of its energy is reflected; on glass, about ______% is reflected.", "blanks": 2}, {"n": 3, "type": "true_false", "prompt": "Metals such as silver and aluminum are shiny because they reflect almost all the frequencies of visible light."}, {"n": 4, "type": "multiple_choice", "prompt": "When a wave traveling along a spring reaches a completely rigid wall, the wave energy is", "options": [{"letter": "a", "text": "almost totally reflected back along the spring"}, {"letter": "b", "text": "totally transmitted into the wall"}, {"letter": "c", "text": "destroyed at the boundary"}]}, {"n": 5, "type": "true_false", "prompt": "If the rigid wall is replaced by a less rigid medium, some wave energy is transmitted and some is still reflected."}]}, {"id": "29.2", "label": "The Law of Reflection", "pageStart": 580, "pageEnd": 580, "items": [{"n": 6, "type": "fill_in", "prompt": "The line perpendicular to a reflecting surface is called the ______.", "blanks": 1}, {"n": 7, "type": "fill_in", "prompt": "The law of reflection states that the angle of ______ and the angle of ______ are equal to each other.", "blanks": 2}, {"n": 8, "type": "true_false", "prompt": "The incident ray, the normal, and the reflected ray all lie in the same plane."}, {"n": 9, "type": "multiple_choice", "prompt": "A pool ball hitting the side of a pool table at an angle bounces back", "options": [{"letter": "a", "text": "at the same angle in a new direction"}, {"letter": "b", "text": "straight along its incoming path"}, {"letter": "c", "text": "at a random angle"}]}, {"n": 10, "type": "true_false", "prompt": "The law of reflection applies only to totally reflected waves, not to partially reflected waves."}]}, {"id": "29.3", "label": "Mirrors", "pageStart": 580, "pageEnd": 582, "items": [{"n": 11, "type": "fill_in", "prompt": "An image that appears to be in a location where light does not really reach is called a ______ image.", "blanks": 1}, {"n": 12, "type": "fill_in", "prompt": "Your image in a plane mirror is as far ______ the mirror as you are in front of it.", "blanks": 1}, {"n": 13, "type": "true_false", "prompt": "Plane mirrors produce only virtual images."}, {"n": 14, "type": "true_false", "prompt": "Light changes frequency when it reflects from a mirror, so your shirt looks a different color in the mirror."}, {"n": 15, "type": "multiple_choice", "prompt": "The virtual image formed by a convex mirror (one that curves outward) is", "options": [{"letter": "a", "text": "larger and farther away than the object"}, {"letter": "b", "text": "smaller and closer to the mirror than the object"}, {"letter": "c", "text": "always the same size as the object"}]}, {"n": 16, "type": "short_answer", "prompt": "Which axis of your body is actually reversed by a plane mirror?"}]}, {"id": "29.4", "label": "Diffuse Reflection", "pageStart": 582, "pageEnd": 583, "items": [{"n": 17, "type": "fill_in", "prompt": "The reflection of light in many directions from a rough surface is called ______ reflection.", "blanks": 1}, {"n": 18, "type": "fill_in", "prompt": "A surface is considered polished if differences in its elevations are less than about one-______ the wavelength of the light that falls on it.", "blanks": 1}, {"n": 19, "type": "true_false", "prompt": "In diffuse reflection, each individual ray still obeys the law of reflection."}, {"n": 20, "type": "multiple_choice", "prompt": "You can read a page of this book from any direction or position because", "options": [{"letter": "a", "text": "the page emits its own light"}, {"letter": "b", "text": "light reflects diffusely in all directions from the rough paper surface"}, {"letter": "c", "text": "the ink absorbs every ray of light"}]}]}, {"id": "29.5", "label": "Reflection of Sound", "pageStart": 583, "pageEnd": 584, "items": [{"n": 21, "type": "fill_in", "prompt": "Reflected sound is called an ______.", "blanks": 1}, {"n": 22, "type": "fill_in", "prompt": "Multiple reflections of sound in a room are called ______.", "blanks": 1}, {"n": 23, "type": "true_false", "prompt": "Sound energy that is not reflected is absorbed or transmitted."}, {"n": 24, "type": "multiple_choice", "prompt": "The study of sound is called", "options": [{"letter": "a", "text": "optics"}, {"letter": "b", "text": "acoustics"}, {"letter": "c", "text": "harmonics"}]}, {"n": 25, "type": "short_answer", "prompt": "Why are the walls of concert halls often designed with grooves?"}]}, {"id": "29.6", "label": "Refraction", "pageStart": 584, "pageEnd": 585, "items": [{"n": 26, "type": "fill_in", "prompt": "The bending of a wave as it crosses the boundary between two media at an angle is called ______.", "blanks": 1}, {"n": 27, "type": "fill_in", "prompt": "Lines that represent the positions of different wave crests are called wave ______.", "blanks": 1}, {"n": 28, "type": "true_false", "prompt": "Water waves travel faster in deep water than in shallow water."}, {"n": 29, "type": "multiple_choice", "prompt": "What causes a wave that crosses a boundary at an angle to bend?", "options": [{"letter": "a", "text": "a change in its speed"}, {"letter": "b", "text": "a change in its amplitude"}, {"letter": "c", "text": "the pull of gravity"}]}, {"n": 30, "type": "true_false", "prompt": "When a wave undergoes refraction, its frequency changes."}]}, {"id": "29.7", "label": "Refraction of Sound", "pageStart": 586, "pageEnd": 586, "items": [{"n": 31, "type": "fill_in", "prompt": "Sound waves are refracted when parts of a wave front travel at different ______.", "blanks": 1}, {"n": 32, "type": "fill_in", "prompt": "Since sound travels faster in ______ air, sound on a hot day tends to bend away from the ground.", "blanks": 1}, {"n": 33, "type": "true_false", "prompt": "On a cold day or at night, when air near the ground is colder than the air above, sound bends toward the ground and carries over longer distances."}, {"n": 34, "type": "multiple_choice", "prompt": "Refraction of sound happens when sound travels through", "options": [{"letter": "a", "text": "perfectly still air of uniform temperature"}, {"letter": "b", "text": "uneven winds or air of uneven temperature"}, {"letter": "c", "text": "a vacuum"}]}]}, {"id": "29.8", "label": "Refraction of Light", "pageStart": 587, "pageEnd": 588, "items": [{"n": 35, "type": "fill_in", "prompt": "When light passes from air into water its rays bend ______ the normal; when it passes from water into air the rays bend ______ from the normal.", "blanks": 2}, {"n": 36, "type": "fill_in", "prompt": "Because of refraction, water in a pond appears to be only three-______ its true depth.", "blanks": 1}, {"n": 37, "type": "true_false", "prompt": "Light paths are reversible for both reflection and refraction."}, {"n": 38, "type": "multiple_choice", "prompt": "Viewed from the bank, a fish in the water appears", "options": [{"letter": "a", "text": "deeper than it really is"}, {"letter": "b", "text": "nearer to the surface and closer than it really is"}, {"letter": "c", "text": "exactly where it really is"}]}, {"n": 39, "type": "true_false", "prompt": "A thick pane of glass viewed straight on appears to be only two-thirds its real thickness."}]}, {"id": "29.9", "label": "Atmospheric Refraction", "pageStart": 588, "pageEnd": 590, "items": [{"n": 40, "type": "fill_in", "prompt": "A distorted image caused by the refraction of light in Earth's atmosphere is called a ______.", "blanks": 1}, {"n": 41, "type": "fill_in", "prompt": "Because of atmospheric refraction at sunrise and sunset, our daytimes are about ______ minutes longer.", "blanks": 1}, {"n": 42, "type": "true_false", "prompt": "A mirage is a trick of the mind and cannot be photographed."}, {"n": 43, "type": "multiple_choice", "prompt": "Light travels faster through the layer of hot air near the ground because", "options": [{"letter": "a", "text": "molecules in hot air are farther apart"}, {"letter": "b", "text": "hot air is denser than cool air"}, {"letter": "c", "text": "hot air carries an electric charge"}]}, {"n": 44, "type": "short_answer", "prompt": "Why does the sun look squashed, like a pumpkin, when it is near the horizon?"}]}, {"id": "29.10", "label": "Dispersion in a Prism", "pageStart": 590, "pageEnd": 590, "items": [{"n": 45, "type": "fill_in", "prompt": "The separation of light into colors arranged according to their frequency is called ______.", "blanks": 1}, {"n": 46, "type": "fill_in", "prompt": "Violet light travels about ______% slower in ordinary glass than red light.", "blanks": 1}, {"n": 47, "type": "true_false", "prompt": "Different frequencies of light travel at different speeds in transparent materials, so they refract and bend at different angles."}, {"n": 48, "type": "multiple_choice", "prompt": "A prism separates white light into colors because", "options": [{"letter": "a", "text": "it adds its own colors to the light"}, {"letter": "b", "text": "different frequencies bend at different angles when refracted twice at nonparallel surfaces"}, {"letter": "c", "text": "it filters out everything except red light"}]}]}, {"id": "29.11", "label": "The Rainbow", "pageStart": 591, "pageEnd": 593, "items": [{"n": 49, "type": "fill_in", "prompt": "To see a rainbow, the sun must shine in one part of the sky while water droplets are in the ______ part of the sky.", "blanks": 1}, {"n": 50, "type": "fill_in", "prompt": "You see red dispersed from raindrops when the angle between the sunbeam and the dispersed light is ______ degrees, and violet at ______ degrees.", "blanks": 2}, {"n": 51, "type": "true_false", "prompt": "All rainbows would be completely round if the ground were not in the way."}, {"n": 52, "type": "multiple_choice", "prompt": "The secondary bow is dimmer than the primary bow because", "options": [{"letter": "a", "text": "it is much farther away"}, {"letter": "b", "text": "most of the light is refracted out the back of the raindrop during the extra reflection"}, {"letter": "c", "text": "it forms only in the evening"}]}, {"n": 53, "type": "short_answer", "prompt": "Why can two people standing side by side never see exactly the same rainbow?"}]}, {"id": "29.12", "label": "Total Internal Reflection", "pageStart": 593, "pageEnd": 595, "items": [{"n": 54, "type": "fill_in", "prompt": "The ______ angle is the angle of incidence that results in light being refracted at 90° with respect to the normal.", "blanks": 1}, {"n": 55, "type": "fill_in", "prompt": "Total internal reflection occurs when the angle of incidence is ______ than the critical angle.", "blanks": 1}, {"n": 56, "type": "true_false", "prompt": "Total internal reflection is total — 100% of the light is reflected back into its original medium."}, {"n": 57, "type": "multiple_choice", "prompt": "The critical angle for a diamond is", "options": [{"letter": "a", "text": "24.6°"}, {"letter": "b", "text": "43°"}, {"letter": "c", "text": "48°"}]}, {"n": 58, "type": "true_false", "prompt": "Optical fibers pipe light from one place to another by a series of total internal reflections."}, {"n": 59, "type": "short_answer", "prompt": "Why are prisms used instead of mirrors in many optical instruments?"}]}]$ch29s$::jsonb,
  $ch29k${"1": ["reflection"], "2": ["2", "4"], "3": "true", "4": "a", "5": "true", "6": ["normal"], "7": ["incidence", "reflection"], "8": "true", "9": "a", "10": "false", "11": ["virtual"], "12": ["behind"], "13": "true", "14": "false", "15": "b", "16": {"model": "The front-back axis is the only axis that is reversed — not left-right or up-down."}, "17": ["diffuse"], "18": ["eighth"], "19": "true", "20": "b", "21": ["echo"], "22": ["reverberations"], "23": "true", "24": "b", "25": {"model": "Grooved walls diffuse the sound, so a listener receives a small amount of reflected sound from many parts of the wall rather than an intense reflection from one part."}, "26": ["refraction"], "27": ["fronts"], "28": "true", "29": "a", "30": "false", "31": ["speeds"], "32": ["warmer"], "33": "true", "34": "b", "35": ["toward", "away"], "36": ["quarters"], "37": "true", "38": "b", "39": "true", "40": ["mirage"], "41": ["5"], "42": "false", "43": "a", "44": {"model": "Rays from the sun's lower edge are bent more than rays from its upper edge, which shortens the vertical diameter and makes the sun look elliptical."}, "45": ["dispersion"], "46": ["1"], "47": "true", "48": "b", "49": ["opposite"], "50": ["42", "40"], "51": "true", "52": "b", "53": {"model": "Each person's cone of vision intersects a different set of raindrops — everybody sees his or her own personal rainbow."}, "54": ["critical"], "55": ["larger"], "56": "true", "57": "a", "58": "true", "59": {"model": "Prisms reflect by total internal reflection, which is 100%, while silvered mirrors reflect only 90 to 95% of the light."}}$ch29k$::jsonb
)
