INSERT INTO concept_exercises (chapter, title, text_pdf_url, page_offset, sections, answer_key)
VALUES (
  30,
  'Lenses',
  'https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte30.pdf',
  601,
  $ch30s$[{"id": "30.1", "label": "Converging and Diverging Lenses", "pageStart": 603, "pageEnd": 604, "items": [{"n": 1, "type": "fill_in", "prompt": "A converging lens, also known as a ______ lens, is thicker in the middle.", "blanks": 1}, {"n": 2, "type": "fill_in", "prompt": "Rays of light that are initially parallel meet, after passing through a converging lens, at a single point called the ______ point.", "blanks": 1}, {"n": 3, "type": "fill_in", "prompt": "The line joining the centers of curvature of a lens's surfaces is called the ______ axis.", "blanks": 1}, {"n": 4, "type": "true_false", "prompt": "A diverging lens is thinner in the middle than at the edges."}, {"n": 5, "type": "multiple_choice", "prompt": "The shape of a lens can be understood by thinking of the lens as a large number of portions of", "options": [{"letter": "a", "text": "mirrors"}, {"letter": "b", "text": "prisms"}, {"letter": "c", "text": "slits"}]}, {"n": 6, "type": "short_answer", "prompt": "Why does a lens have two focal points?"}]}, {"id": "30.2", "label": "Image Formation by a Lens", "pageStart": 604, "pageEnd": 605, "items": [{"n": 7, "type": "fill_in", "prompt": "An image formed by converging light, which can be focused on a screen, is called a ______ image.", "blanks": 1}, {"n": 8, "type": "fill_in", "prompt": "A converging lens magnifies only when the object is between the ______ point and the lens.", "blanks": 1}, {"n": 9, "type": "true_false", "prompt": "A real image formed by a single converging lens is upside down."}, {"n": 10, "type": "multiple_choice", "prompt": "The type of image formed by a lens depends on", "options": [{"letter": "a", "text": "the brightness of the light source"}, {"letter": "b", "text": "the shape of the lens and the position of the object"}, {"letter": "c", "text": "the color of the object"}]}, {"n": 11, "type": "true_false", "prompt": "When a diverging lens is used alone, the image is always virtual, right-side up, and smaller than the object."}]}, {"id": "30.3", "label": "Constructing Images Through Ray Diagrams", "pageStart": 606, "pageEnd": 609, "items": [{"n": 12, "type": "fill_in", "prompt": "In a ray diagram, a ray parallel to the principal axis is refracted by a converging lens so that it passes through the ______ point on the opposite side.", "blanks": 1}, {"n": 13, "type": "fill_in", "prompt": "A ray of light passing through the ______ of the lens continues with no appreciable change in direction.", "blanks": 1}, {"n": 14, "type": "true_false", "prompt": "Any two of the three principal rays are sufficient to locate the relative size and location of an image."}, {"n": 15, "type": "multiple_choice", "prompt": "When the object is between f and 2f from a converging lens, the image is", "options": [{"letter": "a", "text": "beyond 2f from the lens and magnified"}, {"letter": "b", "text": "exactly at the focal point"}, {"letter": "c", "text": "virtual and reduced"}]}, {"n": 16, "type": "true_false", "prompt": "If half a lens is covered, only half of the image is formed."}, {"n": 17, "type": "short_answer", "prompt": "Where is the image when the object sits exactly at the focal point of a converging lens?"}]}, {"id": "30.4", "label": "Image Formation Summarized", "pageStart": 610, "pageEnd": 610, "items": [{"n": 18, "type": "fill_in", "prompt": "A converging lens forms either a real or a virtual image; a diverging lens always forms a ______ image.", "blanks": 1}, {"n": 19, "type": "fill_in", "prompt": "In all cases where a real image is formed, the object and the image are on ______ sides of the lens.", "blanks": 1}, {"n": 20, "type": "true_false", "prompt": "In all cases where a virtual image is formed, the object and the image are on the same side of the lens."}, {"n": 21, "type": "multiple_choice", "prompt": "When the object is close to — but slightly beyond — the focal point of a converging lens, the image is", "options": [{"letter": "a", "text": "far away, as with a slide projector or movie projector"}, {"letter": "b", "text": "inside the lens itself"}, {"letter": "c", "text": "virtual and reduced"}]}]}, {"id": "30.5", "label": "Some Common Optical Instruments", "pageStart": 610, "pageEnd": 612, "items": [{"n": 22, "type": "fill_in", "prompt": "In a camera, the lens forms a real, ______ image on the film or light-detecting chip.", "blanks": 1}, {"n": 23, "type": "fill_in", "prompt": "In a compound microscope, the first lens is called the ______ lens, and the second lens is called the ______.", "blanks": 2}, {"n": 24, "type": "true_false", "prompt": "When you look through a telescope, you are looking at an image of an image."}, {"n": 25, "type": "multiple_choice", "prompt": "Astronomers prefer two-lens telescopes that give inverted images because", "options": [{"letter": "a", "text": "inverted images show finer detail"}, {"letter": "b", "text": "the images are brighter, since no lens transmits 100% of the light"}, {"letter": "c", "text": "stars look better upside down"}]}, {"n": 26, "type": "true_false", "prompt": "Each side of a pair of binoculars uses a pair of prisms to flip the image right-side up."}]}, {"id": "30.6", "label": "The Eye", "pageStart": 612, "pageEnd": 613, "items": [{"n": 27, "type": "fill_in", "prompt": "Light enters the eye through the transparent covering called the ______.", "blanks": 1}, {"n": 28, "type": "fill_in", "prompt": "The ______ is the colored part of the eye, and the ______ is the opening in it through which light passes.", "blanks": 2}, {"n": 29, "type": "true_false", "prompt": "The image formed on the retina is upside down, and the brain compensates by turning the image around."}, {"n": 30, "type": "multiple_choice", "prompt": "In the human eye, most of the focusing is done by the", "options": [{"letter": "a", "text": "retina"}, {"letter": "b", "text": "cornea"}, {"letter": "c", "text": "iris"}]}, {"n": 31, "type": "fill_in", "prompt": "The small region in the center of the field of view where vision is most distinct is called the ______.", "blanks": 1}, {"n": 32, "type": "short_answer", "prompt": "With both eyes open, why don't you notice your blind spots?"}]}, {"id": "30.7", "label": "Some Defects in Vision", "pageStart": 614, "pageEnd": 615, "items": [{"n": 33, "type": "fill_in", "prompt": "A ______ person has trouble focusing on nearby objects because images form behind the retina.", "blanks": 1}, {"n": 34, "type": "fill_in", "prompt": "Nearsightedness is corrected with ______ lenses, and farsightedness is corrected with ______ lenses.", "blanks": 2}, {"n": 35, "type": "true_false", "prompt": "Astigmatism results when the cornea is curved more in one direction than the other."}, {"n": 36, "type": "multiple_choice", "prompt": "The eyeball of a nearsighted eye is", "options": [{"letter": "a", "text": "too long"}, {"letter": "b", "text": "too short"}, {"letter": "c", "text": "missing its lens"}]}, {"n": 37, "type": "true_false", "prompt": "An eye with normal vision can accommodate to see clearly from infinity down to about 25 cm."}]}, {"id": "30.8", "label": "Some Defects of Lenses", "pageStart": 615, "pageEnd": 616, "items": [{"n": 38, "type": "fill_in", "prompt": "The distortions in an image formed by a lens are called ______.", "blanks": 1}, {"n": 39, "type": "fill_in", "prompt": "______ aberration results when light through the edges of a lens focuses differently than light through the center; ______ aberration results from different colors of light traveling at different speeds.", "blanks": 2}, {"n": 40, "type": "true_false", "prompt": "Vision is sharpest when the pupil is smallest, because light then passes through only the center of the eye's lens."}, {"n": 41, "type": "multiple_choice", "prompt": "Chromatic aberration is corrected by using", "options": [{"letter": "a", "text": "achromatic lenses that combine simple lenses of different kinds of glass"}, {"letter": "b", "text": "a single, much thicker lens"}, {"letter": "c", "text": "brighter light"}]}, {"n": 42, "type": "short_answer", "prompt": "How does a diaphragm in a camera reduce spherical aberration?"}]}]$ch30s$::jsonb,
  $ch30k${"1": ["convex"], "2": ["focal"], "3": ["principal"], "4": "true", "5": "b", "6": {"model": "A lens affects light coming from either side in the same way, so there is a focal point and a focal plane on each side."}, "7": ["real"], "8": ["focal"], "9": "true", "10": "b", "11": "true", "12": ["focal"], "13": ["center"], "14": "true", "15": "a", "16": "false", "17": {"model": "The image is at infinity — the rays leave the lens parallel and never converge."}, "18": ["virtual"], "19": ["opposite"], "20": "true", "21": "a", "22": ["inverted"], "23": ["objective", "eyepiece"], "24": "true", "25": "b", "26": "true", "27": ["cornea"], "28": ["iris", "pupil"], "29": "true", "30": "b", "31": ["fovea"], "32": {"model": "One eye fills in the part of the scene to which the other eye is blind."}, "33": ["farsighted"], "34": ["diverging", "converging"], "35": "true", "36": "a", "37": "true", "38": ["aberrations"], "39": ["spherical", "chromatic"], "40": "true", "41": "a", "42": {"model": "It covers the edges of the lens so light passes only through the center, where the aberration is minimal."}}$ch30k$::jsonb
