VALUES (
  31,
  'Diffraction and Interference',
  'https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte31.pdf',
  621,
  $ch31s$[{"id": "31.1", "label": "Huygens' Principle", "pageStart": 623, "pageEnd": 624, "items": [{"n": 1, "type": "fill_in", "prompt": "The idea that every point on a wave front may be regarded as a new point source of secondary waves is called ______ principle.", "blanks": 1}, {"n": 2, "type": "fill_in", "prompt": "Very far from the original source, the wave fronts seem to form a ______.", "blanks": 1}, {"n": 3, "type": "true_false", "prompt": "Huygens stated that light waves spreading out from a point source may be regarded as the overlapping of tiny secondary wavelets."}, {"n": 4, "type": "multiple_choice", "prompt": "When straight water waves pass through an opening that is small compared with the wavelength, the water in the opening acts as", "options": [{"letter": "a", "text": "a barrier that stops the waves"}, {"letter": "b", "text": "a point source of circular waves that fan out beyond the barrier"}, {"letter": "c", "text": "a mirror that reflects the waves"}]}, {"n": 5, "type": "true_false", "prompt": "As the opening in a barrier is made narrower, the spreading of waves into the shadow region becomes less pronounced."}]}, {"id": "31.2", "label": "Diffraction", "pageStart": 625, "pageEnd": 627, "items": [{"n": 6, "type": "fill_in", "prompt": "Any bending of a wave by means other than reflection or refraction is called ______.", "blanks": 1}, {"n": 7, "type": "fill_in", "prompt": "The extent of diffraction depends on the relative size of the ______ compared with the size of the obstruction that casts the shadow.", "blanks": 1}, {"n": 8, "type": "true_false", "prompt": "Long waves fill in shadows better than short waves, which is why foghorns emit low-frequency sound."}, {"n": 9, "type": "multiple_choice", "prompt": "Why do AM radio waves often reach places in mountain canyons that FM waves cannot?", "options": [{"letter": "a", "text": "AM waves are much longer and diffract more readily around obstacles"}, {"letter": "b", "text": "AM waves travel faster than FM waves"}, {"letter": "c", "text": "AM stations broadcast with more energy"}]}, {"n": 10, "type": "true_false", "prompt": "With enough magnification, an optical microscope can show details smaller than the wavelength of visible light."}, {"n": 11, "type": "short_answer", "prompt": "How does a dolphin examine fine detail in its environment?"}]}, {"id": "31.3", "label": "Interference", "pageStart": 628, "pageEnd": 628, "items": [{"n": 12, "type": "fill_in", "prompt": "Within an interference pattern, wave amplitudes may be increased, decreased, or ______.", "blanks": 1}, {"n": 13, "type": "fill_in", "prompt": "When the crest of one wave overlaps the crest of another and their individual effects add together, the result is ______ interference.", "blanks": 1}, {"n": 14, "type": "true_false", "prompt": "In ripple-tank photographs of two vibrating sources, the gray spokes are regions of destructive interference."}, {"n": 15, "type": "multiple_choice", "prompt": "The greater the frequency of the two vibrating sources, the", "options": [{"letter": "a", "text": "farther apart the stripes in the interference pattern"}, {"letter": "b", "text": "closer together the stripes (and the shorter the wavelength)"}, {"letter": "c", "text": "fewer stripes appear"}]}]}, {"id": "31.4", "label": "Young's Interference Experiment", "pageStart": 629, "pageEnd": 630, "items": [{"n": 16, "type": "fill_in", "prompt": "Light of a single color is called ______ light.", "blanks": 1}, {"n": 17, "type": "fill_in", "prompt": "A multitude of closely spaced parallel slits makes up what is called a diffraction ______.", "blanks": 1}, {"n": 18, "type": "true_false", "prompt": "Young's interference experiment convincingly demonstrated the wave nature of light."}, {"n": 19, "type": "multiple_choice", "prompt": "In Young's experiment, a bright fringe occurs on the screen where waves from both slits arrive", "options": [{"letter": "a", "text": "out of phase"}, {"letter": "b", "text": "in phase"}, {"letter": "c", "text": "at different frequencies"}]}, {"n": 20, "type": "true_false", "prompt": "A prism and a diffraction grating separate light into colors by exactly the same process."}, {"n": 21, "type": "short_answer", "prompt": "What produces the iridescent colors in a peacock's feathers?"}]}, {"id": "31.5", "label": "Interference From Thin Films", "pageStart": 631, "pageEnd": 632, "items": [{"n": 22, "type": "fill_in", "prompt": "The phenomenon in which the interference of light waves of mixed frequencies produces a spectrum of colors is known as ______.", "blanks": 1}, {"n": 23, "type": "fill_in", "prompt": "If a soap film is just the right thickness to cancel blue from sunlight, the film appears ______, the complementary color.", "blanks": 1}, {"n": 24, "type": "true_false", "prompt": "A thin film has two closely spaced surfaces, and light reflecting from one surface may cancel light reflecting from the other."}, {"n": 25, "type": "multiple_choice", "prompt": "Extremely small distances are measured with instruments based on interference called", "options": [{"letter": "a", "text": "interferometers"}, {"letter": "b", "text": "spectrometers"}, {"letter": "c", "text": "barometers"}]}, {"n": 26, "type": "true_false", "prompt": "Interference provides the principal method for measuring the wavelengths of light."}]}, {"id": "31.6", "label": "Laser Light", "pageStart": 633, "pageEnd": 634, "items": [{"n": 27, "type": "fill_in", "prompt": "A beam of light that has the same frequency, phase, and direction is said to be ______.", "blanks": 1}, {"n": 28, "type": "fill_in", "prompt": "The word laser comes from light amplification by ______ emission of radiation.", "blanks": 1}, {"n": 29, "type": "true_false", "prompt": "A laser is a source of energy that can put out more energy than it takes in."}, {"n": 30, "type": "multiple_choice", "prompt": "In a helium-neon laser, the coherent beam is produced when", "options": [{"letter": "a", "text": "the helium glows red-hot"}, {"letter": "b", "text": "light emitted by neon stimulates other energized neon atoms to emit light of matched frequency, in cascade"}, {"letter": "c", "text": "sparks jump across the gas tube"}]}, {"n": 31, "type": "true_false", "prompt": "Only a beam of coherent light will not spread and diffuse."}]}, {"id": "31.7", "label": "The Hologram", "pageStart": 635, "pageEnd": 636, "items": [{"n": 32, "type": "fill_in", "prompt": "A hologram is produced by the ______ between two laser light beams on photographic film.", "blanks": 1}, {"n": 33, "type": "fill_in", "prompt": "The part of the laser beam that is reflected from a mirror to the film is called the ______ beam.", "blanks": 1}, {"n": 34, "type": "true_false", "prompt": "If you cut a hologram in half, each half still shows the entire image."}, {"n": 35, "type": "multiple_choice", "prompt": "When you look through an illuminated hologram, you see", "options": [{"letter": "a", "text": "a flat printed photograph"}, {"letter": "b", "text": "a three-dimensional virtual image"}, {"letter": "c", "text": "only a pattern of fringe lines"}]}, {"n": 36, "type": "short_answer", "prompt": "Why are holograms used on credit cards?"}]}]$ch31s$::jsonb,
  $ch31k${"1": ["huygens"], "2": ["plane"], "3": "true", "4": "b", "5": "false", "6": ["diffraction"], "7": ["wavelength"], "8": "true", "9": "a", "10": "false", "11": {"model": "It emits higher-frequency, shorter-wavelength ultrasound, because smaller details are seen with smaller wavelengths."}, "12": ["neutralized"], "13": ["constructive"], "14": "true", "15": "b", "16": ["monochromatic"], "17": ["grating"], "18": "true", "19": "b", "20": "false", "21": {"model": "Tiny ridges in the feathers act as natural diffraction gratings, diffracting light into its component colors."}, "22": ["iridescence"], "23": ["yellow"], "24": "true", "25": "a", "26": "true", "27": ["coherent"], "28": ["stimulated"], "29": "false", "30": "b", "31": "true", "32": ["interference"], "33": ["reference"], "34": "true", "35": "b", "36": {"model": "Holograms are difficult to reproduce, so they deter counterfeiting."}}$ch31k$::jsonb
